"use client";

import Link from "next/link";
import { usePathname, useRouter } from "next/navigation";
import { LayoutDashboard, Users, FileText, FileSpreadsheet, LogOut, Settings } from "lucide-react";
import { createBrowserClient } from "@supabase/ssr";

export default function AdminLayout({ children }: { children: React.ReactNode }) {
  const pathname = usePathname();
  const router = useRouter();

  // Hide layout for login page
  if (pathname === "/admin/login") {
    return <>{children}</>;
  }

  const navItems = [
    { label: "Overview", icon: LayoutDashboard, href: "/admin" },
    { label: "Clients", icon: Users, href: "/admin/clients" },
    { label: "Quotations", icon: FileText, href: "/admin/quotations" },
    { label: "Invoices", icon: FileSpreadsheet, href: "/admin/invoices" },
  ];

  const handleLogout = async () => {
    const supabase = createBrowserClient(
      process.env.NEXT_PUBLIC_SUPABASE_URL!,
      process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
    );
    await supabase.auth.signOut();
    router.push("/admin/login");
    router.refresh();
  };

  return (
    <div className="flex h-screen overflow-hidden bg-background">
      {/* Sidebar Navigation */}
      <aside className="w-64 border-r border-border bg-card hidden md:flex flex-col flex-shrink-0">
        <div className="h-16 flex items-center px-6 border-b border-border text-lg font-bold">
          <span className="h-5 w-5 rounded-sm bg-primary flex items-center justify-center mr-2">
            <span className="w-1.5 h-1.5 bg-white rounded-full"></span>
          </span>
          NexSys OS
        </div>
        <div className="flex-1 py-6 px-4 space-y-2 overflow-y-auto">
          {navItems.map((item) => {
            const isActive = pathname === item.href || (pathname.startsWith(item.href) && item.href !== "/admin");
            return (
              <Link
                key={item.label}
                href={item.href}
                className={`flex items-center gap-3 px-3 py-2 rounded-md transition-colors ${
                  isActive 
                    ? "bg-primary/10 text-primary font-medium" 
                    : "text-muted-foreground hover:bg-secondary/50 hover:text-foreground"
                }`}
              >
                <item.icon className={`h-4 w-4 ${isActive ? "text-primary" : "text-muted-foreground"}`} />
                {item.label}
              </Link>
            );
          })}
        </div>
        <div className="p-4 border-t border-border">
          <button 
            onClick={handleLogout}
            className="flex items-center gap-3 w-full px-3 py-2 text-sm rounded-md text-muted-foreground hover:bg-destructive/10 hover:text-destructive transition-colors"
          >
            <LogOut className="h-4 w-4" />
            Sign Out
          </button>
        </div>
      </aside>

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        {/* Mobile Header (simplified) */}
        <header className="h-16 border-b border-border bg-card flex items-center px-6 md:hidden">
          <div className="text-lg font-bold flex items-center">
            NexSys OS
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-6 md:p-8 relative">
          <div className="absolute top-0 right-0 w-96 h-96 bg-primary/5 rounded-full blur-[100px] -z-10 pointer-events-none" />
          {children}
        </main>
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Plus, Search, MoreHorizontal, FileText, Download, Trash2, Edit } from "lucide-react";
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from "@/components/ui/dropdown-menu";
import Link from "next/link";
import { generatePDF } from "@/utils/pdfGenerator";

export default function QuotationsPage() {
  const [search, setSearch] = useState("");

  // Dummy Data for Preview
  const [quotations] = useState([
    { id: "1", number: "QT-0001", client: "Acme Corp", title: "E-Commerce Replatform", date: "2023-10-01", total: 15400.00, status: "Pending" },
    { id: "2", number: "QT-0002", client: "Stark Industries", title: "AI Integration Module", date: "2023-10-05", total: 45000.00, status: "Accepted" },
    { id: "3", number: "QT-0003", client: "Wayne Enterprises", title: "Security Audit", date: "2023-10-10", total: 8500.00, status: "Rejected" },
  ]);

  const filtered = quotations.filter(q => q.number.toLowerCase().includes(search.toLowerCase()) || q.client.toLowerCase().includes(search.toLowerCase()));

  const handleDownload = (quote: any) => {
    generatePDF({
      type: "Quotation",
      number: quote.number,
      issueDate: quote.date,
      validUntil: "2023-11-01",
      client: {
        name: quote.client,
        company: quote.client,
        email: "client@example.com",
        phone: "+1 555-0000",
        address: "123 Client St."
      },
      items: [
        { service: "Software Architecture", description: quote.title, quantity: 1, unitPrice: quote.total / 1.1, total: quote.total / 1.1 }
      ],
      subtotal: quote.total / 1.1,
      tax: (quote.total / 1.1) * 0.1,
      grandTotal: quote.total
    });
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Quotations</h1>
          <p className="text-muted-foreground mt-1">Create and manage client estimates and proposals.</p>
        </div>

        <Link href="/admin/quotations/create">
          <Button className="glow-primary">
            <Plus className="mr-2 h-4 w-4" /> New Quotation
          </Button>
        </Link>
      </div>

      <div className="flex items-center gap-2 max-w-sm">
        <div className="relative w-full">
          <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
          <Input 
            placeholder="Search quotations..." 
            className="pl-9 bg-card border-border"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>
      </div>

      <div className="rounded-md border border-border bg-card">
        <Table>
          <TableHeader>
            <TableRow className="border-border hover:bg-transparent">
              <TableHead>Quote Number</TableHead>
              <TableHead>Client</TableHead>
              <TableHead>Project Title</TableHead>
              <TableHead>Issue Date</TableHead>
              <TableHead className="text-right">Total</TableHead>
              <TableHead>Status</TableHead>
              <TableHead className="w-[80px]"></TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {filtered.map((quote) => (
              <TableRow key={quote.id} className="border-border hover:bg-secondary/50">
                <TableCell className="font-medium text-primary">{quote.number}</TableCell>
                <TableCell>{quote.client}</TableCell>
                <TableCell>{quote.title}</TableCell>
                <TableCell>{quote.date}</TableCell>
                <TableCell className="text-right font-medium">${quote.total.toFixed(2)}</TableCell>
                <TableCell>
                  <span className={`px-2 py-1 rounded-full text-xs font-medium ${
                    quote.status === 'Accepted' ? 'bg-emerald-500/10 text-emerald-500' : 
                    quote.status === 'Rejected' ? 'bg-destructive/10 text-destructive' :
                    'bg-amber-500/10 text-amber-500'
                  }`}>
                    {quote.status}
                  </span>
                </TableCell>
                <TableCell>
                  <DropdownMenu>
                    <DropdownMenuTrigger render={
                      <Button variant="ghost" className="h-8 w-8 p-0">
                        <span className="sr-only">Open menu</span>
                        <MoreHorizontal className="h-4 w-4" />
                      </Button>
                    } />
                    <DropdownMenuContent align="end" className="bg-card border-border">
                      <DropdownMenuItem className="cursor-pointer hover:bg-secondary hover:text-primary">
                        <Edit className="mr-2 h-4 w-4" /> Edit
                      </DropdownMenuItem>
                      <DropdownMenuItem className="cursor-pointer hover:bg-secondary hover:text-primary" onClick={() => handleDownload(quote)}>
                        <Download className="mr-2 h-4 w-4" /> Download PDF
                      </DropdownMenuItem>
                      <DropdownMenuItem className="cursor-pointer text-destructive focus:bg-destructive/10 focus:text-destructive">
                        <Trash2 className="mr-2 h-4 w-4" /> Delete
                      </DropdownMenuItem>
                    </DropdownMenuContent>
                  </DropdownMenu>
                </TableCell>
              </TableRow>
            ))}
            {filtered.length === 0 && (
              <TableRow>
                <TableCell colSpan={7} className="text-center py-10 text-muted-foreground">
                  No quotations found.
                </TableCell>
              </TableRow>
            )}
          </TableBody>
        </Table>
      </div>
    </div>
  );
}

